/**
 * Embedding Search Benchmark (Bun/TypeScript)
 *
 * Compares FTS5 search against stored embedding similarity for icon lookup.
 * Uses pre-computed embeddings from the database (generated by embed.ts).
 *
 * For the "embedding" search path, this loads the stored embeddings and
 * uses term-overlap scoring as a proxy for query encoding (since the ONNX
 * model cannot be loaded at query time without network access). The real
 * embedding results from the Python version are captured in the benchmark report.
 *
 * Usage: bun run src/build/benchmark-embeddings.ts
 * Requires: data/icons.db with populated icon_embeddings table
 */

import { Database } from "bun:sqlite";

const DB_PATH = "data/icons.db";
const DIMS = 384;

const db = new Database(DB_PATH);

// -- Load all embeddings and icon metadata --
console.log("Loading embeddings...");

interface IconVec {
  name: string;
  label: string;
  searchDoc: string;
  vec: Float32Array;
}

const rows = db
  .prepare(
    `SELECT e.icon_id, e.embedding, i.name, i.label, i.search_terms, i.aliases, i.categories
     FROM icon_embeddings e JOIN icons i ON e.icon_id = i.id`
  )
  .all() as {
  icon_id: number;
  embedding: Buffer;
  name: string;
  label: string;
  search_terms: string | null;
  aliases: string | null;
  categories: string | null;
}[];

const iconVecs: IconVec[] = rows.map((row) => {
  const buf = row.embedding;
  const vec = new Float32Array(buf.buffer, buf.byteOffset, buf.byteLength / 4);

  // Build searchable text for term-overlap scoring
  const parts = [row.label, row.name.replace(/-/g, " ")];
  if (row.search_terms) {
    try { parts.push(...JSON.parse(row.search_terms)); } catch {}
  }
  if (row.aliases) {
    try { parts.push(...JSON.parse(row.aliases).map((a: string) => a.replace(/-/g, " "))); } catch {}
  }
  if (row.categories) {
    try { parts.push(...JSON.parse(row.categories)); } catch {}
  }

  return {
    name: row.name,
    label: row.label,
    searchDoc: parts.join(" ").toLowerCase(),
    vec,
  };
});

console.log(`  ${iconVecs.length} embeddings loaded\n`);

/**
 * Term-overlap "embedding" search: scores icons by how many query terms
 * appear in their search document, weighted by inverse frequency.
 * This is a proxy for real embedding search when the ONNX model is unavailable.
 */
function searchEmbeddingProxy(query: string, topK = 10): { name: string; label: string; score: number }[] {
  const queryTerms = query.toLowerCase().split(/\s+/);

  const scored = iconVecs.map((iv) => {
    let score = 0;
    for (const term of queryTerms) {
      if (iv.searchDoc.includes(term)) {
        // Exact word boundary match scores higher
        const regex = new RegExp(`\\b${term}\\b`);
        if (regex.test(iv.searchDoc)) {
          score += 2;
        } else {
          score += 1;
        }
      }
      // Bonus for name match
      if (iv.name.includes(term) || iv.name.replace(/-/g, " ").includes(term)) {
        score += 3;
      }
    }
    return { name: iv.name, label: iv.label, score };
  });

  scored.sort((a, b) => b.score - a.score);
  return scored.slice(0, topK);
}

/** FTS5 search */
function searchFTS5(query: string, limit = 10): { name: string; rank: number }[] {
  // Check if query looks like a unicode codepoint
  if (query.length >= 4 && /^[0-9a-f]+$/i.test(query)) {
    return db
      .prepare("SELECT name, 0.0 as rank FROM icons WHERE unicode = ? LIMIT ?")
      .all(query.toLowerCase(), limit) as { name: string; rank: number }[];
  }

  const terms = query.split(/\s+/).map((t) => `"${t}"*`).join(" OR ");
  try {
    return db
      .prepare(
        "SELECT name, rank FROM icons_fts WHERE icons_fts MATCH ? ORDER BY rank LIMIT ?"
      )
      .all(terms, limit) as { name: string; rank: number }[];
  } catch {
    return [];
  }
}

// -- Benchmark queries --
const queries: [string, string, string[]][] = [
  ["arrow", "exact", ["arrow-right", "arrow-left", "arrow-up", "arrow-down", "arrow-right-arrow-left"]],
  ["house", "exact", ["house", "house-chimney", "house-user", "house-flag", "house-window"]],
  ["social media", "conceptual", ["facebook", "twitter", "instagram", "linkedin", "reddit", "share", "bluesky"]],
  ["money", "synonym", ["dollar-sign", "money-bill", "coins", "wallet", "money-check"]],
  ["navigation menu", "conceptual", ["bars", "ellipsis", "ellipsis-vertical", "caret-down", "compass"]],
  ["cloud computing", "conceptual", ["cloud", "server", "database", "network-wired", "cloud-arrow-up"]],
  ["spinning loader", "description", ["spinner", "circle-notch", "rotate", "loader", "spinner-third"]],
  ["delete remove", "synonym", ["trash", "xmark", "circle-xmark", "delete-left", "eraser"]],
  ["notification alert", "conceptual", ["bell", "exclamation", "triangle-exclamation", "bell-on", "bell-exclamation"]],
  ["play video", "synonym", ["play", "film", "video", "circle-play", "youtube", "vimeo"]],
  ["user profile", "synonym", ["user", "address-card", "id-card", "circle-user", "user-tie"]],
  ["download file", "synonym", ["download", "file-arrow-down", "cloud-arrow-down", "file-export"]],
  ["chart analytics", "conceptual", ["chart-bar", "chart-line", "chart-pie", "chart-simple", "chart-area"]],
  ["lock security", "conceptual", ["lock", "shield", "key", "unlock", "shield-check"]],
  ["f015", "unicode", ["house"]],
  ["f007", "unicode", ["user"]],
  ["calendar date", "synonym", ["calendar", "calendar-days", "calendar-check", "clock", "calendar-plus"]],
  ["email message", "conceptual", ["envelope", "message", "comment", "paper-plane", "inbox", "mailbox"]],
  ["gear settings", "synonym", ["gear", "gears", "sliders", "wrench", "screwdriver-wrench"]],
  ["heart love", "synonym", ["heart", "heart-pulse", "hand-holding-heart", "face-kiss-wink-heart"]],
];

function precisionAtK(
  results: { name: string }[],
  expected: string[],
  k = 5
): number {
  const topK = results.slice(0, k).map((r) => r.name);
  const hits = topK.filter((n) => expected.includes(n)).length;
  return hits / Math.min(k, expected.length);
}

// -- Run benchmark --
const hdr = (s: string, w: number) => s.padEnd(w);
const rgt = (s: string, w: number) => s.padStart(w);

console.log("=".repeat(90));
console.log(
  `${hdr("Query", 25)} ${hdr("Type", 12)} ${rgt("FTS5 P@5", 10)} ${rgt("Proxy P@5", 10)} ${rgt("FTS5 ms", 10)} ${rgt("Proxy ms", 10)}`
);
console.log("=".repeat(90));

let ftsTotalP5 = 0;
let proxyTotalP5 = 0;
let ftsTotalMs = 0;
let proxyTotalMs = 0;

const typeStats: Record<string, { fts: number[]; proxy: number[] }> = {};

for (const [query, qtype, expected] of queries) {
  // FTS5 (run 100 times for stable timing)
  const t0 = performance.now();
  let ftsResults: { name: string; rank: number }[] = [];
  for (let i = 0; i < 100; i++) {
    ftsResults = searchFTS5(query);
  }
  const ftsMs = (performance.now() - t0) / 100;

  // Term-overlap proxy
  const t1 = performance.now();
  const proxyResults = searchEmbeddingProxy(query);
  const proxyMs = performance.now() - t1;

  const ftsP5 = precisionAtK(ftsResults, expected);
  const proxyP5 = precisionAtK(proxyResults, expected);

  ftsTotalP5 += ftsP5;
  proxyTotalP5 += proxyP5;
  ftsTotalMs += ftsMs;
  proxyTotalMs += proxyMs;

  if (!typeStats[qtype]) typeStats[qtype] = { fts: [], proxy: [] };
  typeStats[qtype].fts.push(ftsP5);
  typeStats[qtype].proxy.push(proxyP5);

  const winner =
    ftsP5 > proxyP5 ? "FTS5" : proxyP5 > ftsP5 ? "Proxy" : "Tie";

  console.log(
    `  "${query}"`.padEnd(25) +
      ` ${qtype.padEnd(12)} ${(ftsP5 * 100).toFixed(0).padStart(7)}%  ${(proxyP5 * 100).toFixed(0).padStart(7)}%  ${ftsMs.toFixed(3).padStart(8)}ms ${proxyMs.toFixed(1).padStart(7)}ms  [${winner}]`
  );

  const ftsNames = ftsResults.slice(0, 5).map((r) => r.name);
  const proxyNames = proxyResults
    .slice(0, 5)
    .map((r) => `${r.name}(${r.score.toFixed(1)})`);
  console.log(`    FTS5:  ${ftsNames.join(", ")}`);
  console.log(`    Proxy: ${proxyNames.join(", ")}`);
}

const n = queries.length;
console.log("\n" + "=".repeat(90));
console.log(
  `  AVERAGES: FTS5 P@5=${((ftsTotalP5 / n) * 100).toFixed(1)}%  Proxy P@5=${((proxyTotalP5 / n) * 100).toFixed(1)}%  FTS5=${(ftsTotalMs / n).toFixed(3)}ms  Proxy=${(proxyTotalMs / n).toFixed(1)}ms`
);

console.log("\n  BY TYPE:");
for (const qtype of Object.keys(typeStats).sort()) {
  const stats = typeStats[qtype];
  const ftsAvg = stats.fts.reduce((a, b) => a + b, 0) / stats.fts.length;
  const proxyAvg =
    stats.proxy.reduce((a, b) => a + b, 0) / stats.proxy.length;
  const winner =
    ftsAvg > proxyAvg ? "FTS5" : proxyAvg > ftsAvg ? "Proxy" : "Tie";
  console.log(
    `    ${qtype.padEnd(15)} FTS5=${(ftsAvg * 100).toFixed(0)}%  Proxy=${(proxyAvg * 100).toFixed(0)}%  Winner=${winner}`
  );
}

console.log("\n  CONCLUSION:");
let proxyWins = 0;
let ftsWins = 0;
for (const [query, , expected] of queries) {
  const fp = precisionAtK(searchFTS5(query), expected);
  const pp = precisionAtK(searchEmbeddingProxy(query), expected);
  if (pp > fp) proxyWins++;
  else if (fp > pp) ftsWins++;
}
const ties = queries.length - proxyWins - ftsWins;
console.log(`    Proxy wins: ${proxyWins}/${queries.length}`);
console.log(`    FTS5 wins: ${ftsWins}/${queries.length}`);
console.log(`    Ties: ${ties}/${queries.length}`);
console.log(
  `    FTS5 avg: ${(ftsTotalMs / n).toFixed(3)}ms, Proxy avg: ${(proxyTotalMs / n).toFixed(1)}ms`
);
console.log(
  "\n  NOTE: Proxy uses term-overlap scoring, not real embeddings."
);
console.log(
  "  For true embedding benchmark results, see the Python version output."
);

db.close();
